import React, { useState, useEffect, useRef } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { setQuery, setLocation } from "../../store";
import { setLoginOpen } from "../../store";
import "./Header.css";

const POPULAR_SEARCHES = [
  { icon: "fa-magnifying-glass", text: "Software Companies" },
  { icon: "fa-magnifying-glass", text: "Web Development Services" },
  { icon: "fa-code", text: "Mobile App Developers" },
  { icon: "fa-bullhorn", text: "Digital Marketing Agencies" },
];


const POPULAR_CITIES = [
  "Chennai", "Coimbatore", "Madurai", "Tiruchirappalli", "Salem",
  "Tiruppur", "Erode", "Tuticorin", "Tirunelveli", "Dindigul",
  "Thanjavur", "Ooty", "Kodaikanal", "Yercaud", "Bangalore",
  "Mumbai", "Delhi", "Hyderabad", "Kolkata", "Pune",
  "Ahmedabad", "Jaipur", "Chandigarh", "Lucknow", "Kochi",
  "Visakhapatnam", "Mysore", "Bhopal", "Noida", "Vijayawada",
];


export default function Header() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { query, location } = useSelector((s) => s.search);
  const [scrolled, setScrolled] = useState(false);
  const [showDrop, setShowDrop] = useState(false);
  const [isMobileModalOpen, setIsMobileModalOpen] = useState(false);
  const [filtered, setFiltered] = useState(POPULAR_SEARCHES);
  const [city, setCity] = useState(POPULAR_CITIES?.[0] || "");

  const inputRef = useRef(null);
  const dropRef = useRef(null);

  const isMobileSize = () => window.innerWidth < 992;

  /* Sticky header controller */
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  /* Close desktop dropdown when clicking outside */
  useEffect(() => {
    const handler = (e) => {
      if (
        dropRef.current &&
        !dropRef.current.contains(e.target) &&
        inputRef.current &&
        !inputRef.current.contains(e.target)
      ) {
        setShowDrop(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  /* Sync body scrolling lock toggle when Mobile Overlay mounts */
  useEffect(() => {
    if (isMobileModalOpen) document.body.style.overflow = "hidden";
    else document.body.style.overflow = "unset";
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [isMobileModalOpen]);

  const handleInput = (e) => {
    const val = e.target.value;
    dispatch(setQuery(val));
    const f = POPULAR_SEARCHES.filter((i) =>
      i.text.toLowerCase().includes(val.toLowerCase()),
    );
    setFiltered(f);
    setShowDrop(val.length > 0 ? f.length > 0 : true);
  };

  const handleSelect = (text) => {
    dispatch(setQuery(text));
    setShowDrop(false);
    setIsMobileModalOpen(false);
    navigate("/category");
  };

  const handleFocus = () => {
    if (isMobileSize()) {
      inputRef.current?.blur();
      setIsMobileModalOpen(true);
      return;
    }
    setFiltered(query ? filtered : POPULAR_SEARCHES);
    setShowDrop(true);
  };

  return (
    <>
      <header className={`site-header${scrolled ? " scrolled" : ""}`}>
        <div className="container">
          <div className="row header-inner">
            {/* Mobile: brand row */}
            <div className="col brand-row">
              <Link to="/" className="brand-link">
                <div className="brand-name">Infotell</div>
              </Link>
              <button
                className="mobile-login-btn"
                onClick={() => dispatch(setLoginOpen(true))}
              >
                Login
              </button>
            </div>

            {/* Search Bar - Layers and mobile interception added */}
            <div
              className="col search-relative"
              ref={dropRef}
              style={{
                position: "relative",
                zIndex: showDrop ? 99999 : 2,
              }}
              onClick={() => {
                if (isMobileSize()) setIsMobileModalOpen(true);
              }}
            >
              <div className="search-wrapper">
                {/* <div
                  className="location-box"
                  onClick={(e) => {
                    if (isMobileSize()) e.stopPropagation();
                  }}
                >
                  <i className="fa-solid fa-location-dot"></i>
                  <input
                    type="text"
                    className="location-input"
                    value={location}
                    onChange={(e) => dispatch(setLocation(e.target.value))}
                  />
                </div> */}
                  <i className="fa-solid fa-location-dot"></i>
                  <select
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    onClick={(e) => {
                      if (isMobileSize()) e.stopPropagation();
                    }}
                    className="location-box"
                    aria-label="Select City"
                  >
                    {POPULAR_CITIES.map((c) => (
                      <option key={c} value={c}>
                        {c}
                      </option>
                    ))}
                  </select>

                <div className="search-input-box" id="searchBox">
                  <i className="fa-solid fa-magnifying-glass"></i>
                  <input
                    ref={inputRef}
                    id="searchInput"
                    type="text"
                    className="search-input"
                    placeholder="Search for Services, Shops, or Companies"
                    value={query}
                    onChange={handleInput}
                    onFocus={handleFocus}
                    readOnly={isMobileSize()} /* Prevents keyboard flash before overlay opens */
                    autoComplete="off"
                  />
                  <i className="fa-solid fa-microphone mic-icon"></i>
                </div>
                <button
                  className="search-btn"
                  onClick={(e) => {
                    e.stopPropagation();
                    navigate("/category");
                  }}
                >
                  <i className="fa-solid fa-arrow-right"></i>
                </button>
              </div>

              {/* Desktop Dropdown Box Panel */}
              {showDrop && !isMobileSize() && (
                <div className="search-dropdown" id="searchDropdown">
                  <div className="search-dropdown-label">Popular Searches</div>
                  {filtered.map((item, idx) => (
                    <div
                      key={idx}
                      className="search-item"
                      onClick={() => handleSelect(item.text)}
                    >
                      <i className={`fa-solid ${item.icon}`}></i>
                      <span>{item.text}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Desktop Actions Layout Panel */}
            <div className="header-actions">
              <button
                className="login-btn"
                onClick={() => dispatch(setLoginOpen(true))}
              >
                Sign Up
              </button>
              <button className="btn-listing" aria-label="Add Listing">
                Add Listing
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Modern High Contrast Mobile Screen Overhaul Modal Overlay */}
      {isMobileModalOpen && (
        <div className="search-overlay">
          <div className="search-overlay-header">
            <button
              className="back-btn"
              onClick={() => setIsMobileModalOpen(false)}
            >
              ←
            </button>
          </div>

          <div className="search-overlay-bar-wrapper">
            <div className="overlay-location-picker">
              <i className="fa-solid fa-location-dot loc-icon"></i>
              <input
                type="text"
                className="overlay-city-select"
                value={location}
                onChange={(e) => dispatch(setLocation(e.target.value))}
              />
            </div>
            <i className="fa-solid fa-magnifying-glass bar-search-icon"></i>
            <input
              type="text"
              autoFocus
              placeholder="Search for Services, Shops..."
              value={query}
              onChange={handleInput}
              onKeyDown={(e) => e.key === "Enter" && handleSelect(query)}
              className="overlay-main-input"
            />
            <i className="fa-solid fa-microphone mic-btn"></i>
          </div>

          <div className="search-overlay-content">
            <h3 className="trending-title">
              {query ? "Matching Results" : "Popular Searches"}
            </h3>
            <div className="trending-list">
              {filtered.map((item, idx) => (
                <div
                  key={idx}
                  className="trending-item"
                  onClick={() => handleSelect(item.text)}
                >
                  <div className="trending-icon-box">
                    <i className={`fa-solid ${item.icon}`}></i>
                  </div>
                  <div className="trending-text-box">
                    <span className="trending-name">{item.text}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  );
}
